sql:
SELECT AVG(query_duration) AS avg_query_duration
FROM connections
WHERE status = 'active';

SELECT status
FROM connections
WHERE connection_id = 1;

SELECT setting_name, COUNT(*) AS total_settings
FROM settings
GROUP BY setting_name;
